import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  return (
    <nav className="navbar">
      <div className="navbar-inner">
        {/* LEFT - LOGO */}
        <Link
          to="/"
          style={{
            fontSize: "20px",
            fontWeight: "600",
            color: "#111",
          }}
        >
          SubManager
        </Link>

        {/* RIGHT SIDE */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: "18px",
          }}
        >
          {user ? (
            <>
              <Link to="/tasks" style={{ color: "#555" }}>
                Subscriptions
              </Link>

              <Link to="/profile" style={{ color: "#555" }}>
                Profile
              </Link>

              {/* ADMIN LINK */}
              {user.role === "admin" && (
                <Link
                  to="/admin"
                  style={{
                    color: "#4f46e5",
                    fontWeight: "500",
                  }}
                >
                  Admin
                </Link>
              )}

              {/* ROLE BADGE */}
              <span
                style={{
                  background: "#f3f4f6",
                  padding: "4px 10px",
                  borderRadius: "999px",
                  fontSize: "12px",
                  color: "#555",
                  textTransform: "capitalize",
                }}
              >
                {user.role}
              </span>

              {/* LOGOUT */}
              <button onClick={handleLogout} className="btn-danger">
                Logout
              </button>
            </>
          ) : (
            <>
              <Link to="/login" style={{ color: "#555" }}>
                Login
              </Link>

              <Link to="/register" className="btn-primary">
                Register
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
